#include <string>
#include <vector>
bool solve(const std::string& s){
  std::vector<char> st;
  auto match=[&](char o,char c){ return (o=='('&&c==')')||(o=='['&&c==']')||(o=='{'&&c=='}'); };
  for(char ch: s){
    if(ch=='('||ch=='['||ch=='{') st.push_back(ch);
    else if(ch==')'||ch==']'||ch=='}'){
      if(st.empty()) return false;
      char top=st.back(); st.pop_back();
      if(!match(top,ch)) return false;
    }
  }
  return st.empty();
}

