#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>
std::vector<std::string> solve(const std::vector<std::string>& arr, int k){
  std::unordered_map<std::string,int> freq;
  for (auto& x : arr) freq[x]++;
  std::vector<std::pair<std::string,int>> list(freq.begin(), freq.end());
  std::sort(list.begin(), list.end(), [](auto& a, auto& b){ return a.second > b.second; });
  if (k > (int)list.size()) k = (int)list.size();
  std::vector<std::string> out;
  for (int i=0;i<k;i++) out.push_back(list[i].first);
  return out;
}

