#include <vector>
int solve(const std::vector<long long>& arr, long long target){
  int lo=0, hi=(int)arr.size()-1;
  while (lo<=hi) {
    int mid=(lo+hi)/2;
    if (arr[mid]==target) return mid;
    if (arr[mid]<target) lo=mid+1; else hi=mid-1;
  }
  return -1;
}

