// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
#include <string>
#include <cctype>

bool solve(const std::string& rut){
  std::string clean;
  for(char c: rut){
    if(c=='.' || c=='-' || std::isspace((unsigned char)c)) continue;
    clean.push_back((char)std::toupper((unsigned char)c));
  }
  if(clean.size() < 2) return false;

  char dv = clean.back();
  std::string body = clean.substr(0, clean.size()-1);

  for(char c: body) if(!std::isdigit((unsigned char)c)) return false;

  int sum=0, mul=2;
  for(int i=(int)body.size()-1; i>=0; --i){
    int d = body[i]-'0';
    sum += d * mul;
    mul = (mul==7)?2:(mul+1);
  }

  int mod = 11 - (sum % 11);
  char dvCalc = (mod==11)?'0':(mod==10)?'K':(char)('0'+mod);
  return dv == dvCalc;
}

