std::vector<int> bfs(const std::vector<std::vector<int>>& g, int start){
  std::queue<int> q;
  std::vector<char> seen(g.size(), 0);
  std::vector<int> out;

  q.push(start); seen[start]=1;
  while(!q.empty()){
