// C0668 · A* (pathfinding) (Avanzado, Algoritmos)
#include <vector>
#include <queue>
#include <unordered_map>
#include <cmath>

struct Node { int x,y; int f; };
struct Cmp { bool operator()(const Node& a, const Node& b) const { return a.f > b.f; } };
static int hcost(int x,int y,int gx,int gy){ return std::abs(x-gx)+std::abs(y-gy); }
static int key(int x,int y,int w){ return y*w + x; }

std::vector<std::pair<int,int>> solve(const std::vector<std::vector<int>>& grid, std::pair<int,int> start, std::pair<int,int> goal){
  int h = (int)grid.size(), w = (int)grid[0].size();
  int sx=start.first, sy=start.second, gx=goal.first, gy=goal.second;

  std::priority_queue<Node, std::vector<Node>, Cmp> open;
  std::vector<int> gscore(w*h, INT32_MAX);
  std::vector<int> came(w*h, -1);

  int sidx = key(sx,sy,w);
  gscore[sidx] = 0;
  open.push({sx,sy,hcost(sx,sy,gx,gy)});

  auto neighbors = [&](int x,int y){
    std::vector<std::pair<int,int>> out;
    const int dx[4]={1,-1,0,0};
    const int dy[4]={0,0,1,-1};
    for(int i=0;i<4;i++){
      int nx=x+dx[i], ny=y+dy[i];
      if(nx>=0 && ny>=0 && nx<w && ny<h && grid[ny][nx]==0) out.push_back({nx,ny});
    }
    return out;
  };

  while(!open.empty()){
    Node cur = open.top(); open.pop();
    if(cur.x==gx && cur.y==gy){
      std::vector<std::pair<int,int>> path;
      int idx = key(gx,gy,w);
      while(idx != -1){
        int x = idx % w, y = idx / w;
        path.push_back({x,y});
        idx = came[idx];
      }
      std::reverse(path.begin(), path.end());
      return path;
    }
    int cidx = key(cur.x,cur.y,w);
    for(auto [nx,ny] : neighbors(cur.x,cur.y)){
      int nidx = key(nx,ny,w);
      int ng = gscore[cidx] + 1;
      if(ng < gscore[nidx]){
        gscore[nidx]=ng;
        came[nidx]=cidx;
        open.push({nx,ny, ng + hcost(nx,ny,gx,gy)});
      }
    }
  }
  return {};
}

