// C0669 · LRU cache (Intermedio, Algoritmos)
#include <unordered_map>
#include <list>

class LRU {
  using ListIt = std::list<int>::iterator;
  int cap;
  std::list<int> order;
  std::unordered_map<int, std::pair<int, ListIt>> map; // key -> (value, iterator)
public:
  explicit LRU(int cap): cap(cap) {}

  int get(int key){
    auto it = map.find(key);
    if(it == map.end()) return -1;
    order.erase(it->second.second);
    order.push_back(key);
    it->second.second = std::prev(order.end());
    return it->second.first;
  }

  void put(int key, int val){
    auto it = map.find(key);
    if(it != map.end()){
      order.erase(it->second.second);
      order.push_back(key);
      it->second = {val, std::prev(order.end())};
      return;
    }
    if((int)map.size() == cap){
      int oldest = order.front();
      order.pop_front();
      map.erase(oldest);
    }
    order.push_back(key);
    map[key] = {val, std::prev(order.end())};
  }
};

