#include <cctype>

int solve(){
  std::cout << "Escribe una tecla y Enter (w/a/s/d, q):\n";
  std::string line;
  while (std::getline(std::cin, line)) {
    if (line.empty()) continue;
    char k = std::tolower(static_cast<unsigned char>(line[0]));
    if (k=='q') break;
    if (k=='w') std::cout << "Mover: arriba\n";
    if (k=='s') std::cout << "Mover: abajo\n";
    if (k=='a') std::cout << "Mover: izquierda\n";
    if (k=='d') std::cout << "Mover: derecha\n";
  }
  return 0;
}

